19	                                                an<ConfigResource> resource) {
20	  if (!boost::ends_with(resource->resource_id, ".schema"))
21	    return true;
22	  if (auto preset = resource->data->Traverse("key_binder/import_preset")) {
23	    if (!Is<ConfigValue>(preset))
24	      return false;
25	    auto preset_config_id = As<ConfigValue>(preset)->str();
26	    LOG(INFO) << "interpreting key_binder/import_preset: " << preset_config_id;
27	    auto target = Cow(resource, "key_binder");
28	    auto map = As<ConfigMap>(**target);
29	    if (map && map->HasKey("bindings")) {
30	      // append to included list `key_binder/bindings/+` instead of overwriting
31	      auto appended = map->Get("bindings");
32	      *Cow(target, "bindings/+") = appended;
33	      // `*target` is already referencing a copied map, safe to edit directly
34	      (*target)["bindings"] = nullptr;
35	    }
36	    Reference reference{preset_config_id, "key_binder", false};
37	    if (!IncludeReference{reference}.TargetedAt(target).Resolve(compiler)) {
38	      LOG(ERROR) << "failed to include section " << reference;
39	      return false;
40	    }
41	  }
42	  // NOTE: in the following cases, Cow() is not strictly necessary because
43	  // we know for sure that no other ConfigResource is going to reference the
44	  // root map node that will be modified. But other than the root node of the
45	  // resource being linked, it's possible a map or list has multiple references
46	  // in the node tree, therefore Cow() is recommended to make sure the
47	  // modifications only happen to one place.
48	  if (auto preset = resource->data->Traverse("punctuator/import_preset")) {
49	    if (!Is<ConfigValue>(preset))
50	      return false;
51	    auto preset_config_id = As<ConfigValue>(preset)->str();
52	    LOG(INFO) << "interpreting punctuator/import_preset: " << preset_config_id;
53	    Reference reference{preset_config_id, "punctuator", false};
54	    if (!IncludeReference{reference}
55	             .TargetedAt(Cow(resource, "punctuator"))
56	             .Resolve(compiler)) {
57	      LOG(ERROR) << "failed to include section " << reference;
58	      return false;
59	    }
60	  }
61	  if (auto preset = resource->data->Traverse("recognizer/import_preset")) {
62	    if (!Is<ConfigValue>(preset))
63	      return false;
64	    auto preset_config_id = As<ConfigValue>(preset)->str();
65	    LOG(INFO) << "interpreting recognizer/import_preset: " << preset_config_id;
66	    Reference reference{preset_config_id, "recognizer", false};
67	    if (!IncludeReference{reference}
68	             .TargetedAt(Cow(resource, "recognizer"))
69	             .Resolve(compiler)) {
70	      LOG(ERROR) << "failed to include section " << reference;
71	      return false;
72	    }
73	  }
74	  return true;
